class Box<T> {
    private T content;
    public void set(T t) { this.content = t; }
    public T get() { return content; }
}

public class Main {
    public static void main(String[] args) {
        Box<String> stringBox = new Box<>();
        stringBox.set("Gift");
        System.out.println(stringBox.get());
    }
}
